  ('judicial-cf446b4c-moex-00474', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '質權人於占有或保管質物時，應負何種注意義務？', '["善良管理人之注意義務", "一般人之注意義務", "與處理自己事務同一注意義務", "通常事變之注意義務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00475', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '下列關於親權之敘述，何者正確？', '["成年在學學生仍有受扶養必要，故仍應服從父母之親權", "對於未成年子女之親權，以父母共同行使為原則", "非婚生子女經生父認領者，即應服從生父之親權", "未成年人父母雙亡者，應由同居之祖父母任親權人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00476', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲與乙訂立買賣契約後，甲受監護宣告。甲對於債務不履行是否應負責任？', '["甲無行為能力，即使在心神回復中亦毋須負擔債務不履行責任", "甲即使在心神回復中，若其監護宣告未被撤銷，對於債務不履行毋須負責", "甲若無識別能力，對於債務不履行毋須負責", "甲受監護宣告後無法享受權利與負擔義務，對於債務不履行毋須負責"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00477', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲出售其所有置放於甲之住所的A車予乙，雙方約定於締約1週後，由乙至甲之住所受領該車。 下列敘述，何者錯誤？', '["乙依約至甲處受領A車時，如甲拒絕給付，甲即負遲延責任", "乙未依約至甲處受領A車時，甲不負遲延責任", "乙未依約至甲處受領A車時，甲僅就故意或重大過失負繼續保管A車之責任", "甲所負之債務，稱為「赴償債務」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00001', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '下列何項原則不屬於罪刑法定原則之內涵？', '["禁止類推適用原則", "罪刑明確性原則", "不利益變更禁止原則", "禁止溯及既往原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00002', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '有關法律變更的敘述，下列何者正確？', '["依刑法第2條第1項本文之規定，行為後法律有變更時，原則上適用裁判時之法律", "刑法第2條第1項所稱之法律，僅限於涉及犯罪成立之要件，而不含刑罰效果", "依刑法第2條第2項之規定，沒收與所有的保安處分均適用裁判時之法律", "刑罰之內容於行為後有變更者，結論上應適用最有利於行為人之法律"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00003', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '依刑法規定、實務及通說見解，下列何者之情形不該當刑法上之重傷概念？', '["甲將乙右手大拇指、食指及中指砍斷，僅留無名指與小指", "甲用球棒毆打乙，使乙之膝關節無法伸直", "甲用球棒毆打乙，使乙昏迷成為植物人", "甲用球棒毆打乙，使乙腳骨折經一年復健始能正常行走"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00004', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '甲為A上市公司執行長，某日酒駕肇事，乃與坐在副手座的乙交換，並提供新臺幣300萬元安家費，要乙 承認自己為駕駛人。依實務見解，下列何者正確？', '["甲成立刑法第164條第2項意圖隱避犯人頂替罪之教唆犯", "乙成立刑法第164條第2項意圖隱避犯人頂替罪之幫助犯", "甲成立刑法第164條第2項的意圖隱避犯人頂替罪", "乙成立刑法第164條第2項的意圖隱避犯人頂替罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00005', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '有關罪刑法定原則，下列敘述何者錯誤？', '["其目的在防止國家濫用刑罰，並藉此保障人民權利", "國家必須事先以成文法律明確規定犯罪要件與制裁內容", "習慣法不得作為成立犯罪之依據", "保安處分一律適用裁判時之法律"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00006', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-114-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '意圖抬高交易價格，囤積下列何種物品，無正當理由不應市銷售者，不構成刑法第251條不法囤積物品哄 抬價格牟利罪？', '["糧食、農產品或其他民生必需之飲食物品", "種苗、肥料、原料或其他農業、工業必需之物品", "經行政院公告之生活必需用品", "衣服、鞋子等服飾物品"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL)
